        field: 'subject',
        operation: 'notContains',
        values: ['unsubscribe', 'spam', 'advertisement'],
        weight: 1,
      };

      const result = matchRulePattern(email, rule);

      expect(result.matched).toBe(false);
      expect(result.matchedValue).toBe('');
    });

