});

/**
 * Create detailed email for integration testing
 */
function createDetailedEmail(id: string, subject: string, fromEmail: string): EmailMessage {
  const fromName = fromEmail.split('@')[0];
  const bodyContent = `This is a test email with subject: ${subject}\n\nThis email is from ${fromEmail} for integration testing purposes.`;

  return {
    id,
    threadId: `thread-${id}`,
    gmailLabels: ['INBOX', 'UNREAD'],
    payload: {
      mimeType: 'multipart/alternative',
      headers: [
        { name: 'Subject', value: subject },
        { name: 'From', value: `${fromName} <${fromEmail}>` },
        { name: 'To', value: 'test-user@example.com' },
        { name: 'Date', value: new Date().toUTCString() },
        { name: 'Message-ID', value: `<${id}@mail.example.com>` },
      ],
      body: {
        data: Buffer.from(bodyContent).toString('base64'),
      },
      parts: [
        {
          partId: '0',
          mimeType: 'text/plain',
          headers: [],
          body: {
            data: Buffer.from(bodyContent).toString('base64'),
          },
        },
        {
          partId: '1',
          mimeType: 'text/html',
          headers: [],
          body: {
            data: Buffer.from(`<html><body><p>${bodyContent}</p></body></html>`).toString('base64'),
          },
        },
      ],
    },
    subject,
    from: {
      email: fromEmail,
      name: fromName,
      raw: `${fromName} <${fromEmail}>`,
    },
    to: [
      {
        email: 'test-user@example.com',
        name: 'Test User',
        raw: 'Test User <test-user@example.com>',
      },
    ],
    date: new Date(),
    bodyPlain: bodyContent,
    bodyHtml: `<html><body><p>${bodyContent}</p></body></html>`,
    isProcessed: false,
    processingPriority: 50,
  };
}

