        console.log(`  Overhead: ${formatDuration(totalDurationMs - result.processingDurationMs)}`);
        console.log(`  Target: ${formatDuration(PERFORMANCE_THRESHOLDS.MAX_TOTAL_PROCESSING_TIME_MS)}`);
