/**
 * Performance Validation and Benchmarking Tests (T049)
 *
 * TDD APPROACH: These tests establish the performance contract BEFORE optimization.
 * Tests will initially FAIL - that's expected and correct for TDD red-green-refactor.
 *
 * Performance Targets (FR-005):
 * - Single email processing: < 10 seconds per email (total end-to-end)
 * - Classification engine: < 5 seconds per email (classification only)
 * - Batch processing: Support parallel execution
 * - Memory: Reasonable heap usage during batch operations
 * - Throughput: Measure emails/second for batch operations
 *
 * Test Strategy:
 * - Measure baseline performance before T073 optimization
 * - Establish clear pass/fail thresholds
 * - Track performance metrics across different scenarios
 * - Validate parallel processing capabilities
 *
 * Note: These tests use REAL classification pipeline (not mocked) to measure actual performance.
 * AI client is mocked for deterministic, fast results.
 */

import { ClassificationOrchestrator } from '../../src/orchestrator/classification-orchestrator';
import { ClassificationPipeline } from '@gmail-automation/classification-engine';
import type { EmailMessage, CategoryConfiguration } from '@gmail-automation/classification-engine';
import { validMinimalCategoryConfig } from '../../../classification-engine/tests/fixtures/configs';
import { MockAIClient } from '../helpers/mock-ai-client';

/**
 * Performance thresholds per FR-005 and Constitutional Principle IV
 */
const PERFORMANCE_THRESHOLDS = {
  // Total end-to-end processing time per email (orchestrator + classification + overhead)
  MAX_TOTAL_PROCESSING_TIME_MS: 10_000, // 10 seconds

  // Classification engine only (without orchestration overhead)
  MAX_CLASSIFICATION_TIME_MS: 5_000, // 5 seconds

  // Stretch goal for optimized performance (200% safety margin)
  STRETCH_GOAL_MS: 3_000, // 3 seconds

  // Memory constraints
  MAX_HEAP_GROWTH_MB: 100, // Maximum heap growth during batch processing

  // Throughput targets
  MIN_THROUGHPUT_EMAILS_PER_SECOND: 0.1, // At least 1 email per 10 seconds
  OPTIMAL_THROUGHPUT_EMAILS_PER_SECOND: 0.33, // 1 email per 3 seconds (stretch goal)
} as const;

/**
 * Test configuration
 */
const TEST_CONFIG = {
  // Number of emails to test in batch scenarios
  BATCH_SIZE_SMALL: 10,
  BATCH_SIZE_MEDIUM: 50,
  BATCH_SIZE_LARGE: 100,

  // Timeout for performance tests (allow time for slow baseline)
  PERFORMANCE_TEST_TIMEOUT_MS: 300_000, // 5 minutes for batch tests
} as const;

/**
 * Helper: Create realistic test email with varied content
 */
function createTestEmail(id: string, subject: string, fromEmail: string, bodySnippet?: string): EmailMessage {
  const fromName = fromEmail.split('@')[0];
  const bodyContent = bodySnippet || `Test email body for ${subject}`;

  return {
    id,
    threadId: `thread-${id}`,
    gmailLabels: ['INBOX', 'UNREAD'],
    snippet: bodyContent.substring(0, 100),
    payload: {
      mimeType: 'text/plain',
      headers: [
        { name: 'Subject', value: subject },
        { name: 'From', value: `${fromName} <${fromEmail}>` },
        { name: 'To', value: 'test-user@example.com' },
        { name: 'Date', value: new Date().toUTCString() },
      ],
      body: {
        size: bodyContent.length,
        data: Buffer.from(bodyContent).toString('base64'),
      },
      parts: [],
    },
    subject,
    from: {
      email: fromEmail,
      name: fromName,
      raw: `${fromName} <${fromEmail}>`,
    },
    to: [
      {
        email: 'test-user@example.com',
        name: 'Test User',
        raw: 'Test User <test-user@example.com>',
      },
    ],
    date: new Date(),
    bodyPlain: bodyContent,
    sizeEstimate: 5000,
    historyId: '12345',
    isProcessed: false,
    processingPriority: 50,
  };
}

/**
 * Helper: Generate batch of varied test emails to simulate realistic workload
 */
function generateTestEmailBatch(count: number): EmailMessage[] {
  const subjects = [
    'Your Amazon order #123 has shipped',
    'Weekly project status update',
    'URGENT: Security alert for your account',
    'Fwd: Meeting notes from Monday',
    'Receipt for your recent purchase',
    'Newsletter: Tech industry trends',
    'Your invoice #456 is ready',
    'Team lunch this Friday?',
    'Promotion: 50% off this weekend',
    'System notification: Backup completed',
  ];

  const senders = [
    'shipment@amazon.com',
    'project-manager@company.com',
    'security@service.com',
    'colleague@company.com',
    'receipts@store.com',
    'newsletter@techblog.com',
    'billing@vendor.com',
    'team-member@company.com',
    'promotions@retailer.com',
    'noreply@system.com',
  ];

  return Array.from({ length: count }, (_, i) => {
    const subjectIndex = i % subjects.length;
    const senderIndex = i % senders.length;
    return createTestEmail(
      `msg-${String(i).padStart(4, '0')}`,
      subjects[subjectIndex],
      senders[senderIndex],
      `This is test email ${i + 1} of ${count} with realistic content for performance testing.`
    );
  });
}

/**
 * Helper: Measure memory usage
 */
function getMemoryUsageMB(): number {
  const usage = process.memoryUsage();
  return usage.heapUsed / 1024 / 1024;
}

/**
 * Helper: Format duration for reporting
 */
function formatDuration(ms: number): string {
  if (ms < 1000) return `${ms.toFixed(0)}ms`;
  return `${(ms / 1000).toFixed(2)}s`;
}

describe('Performance Validation and Benchmarking (T049 - TDD)', () => {
  let orchestrator: ClassificationOrchestrator;
  let mockAIClient: MockAIClient;

  beforeEach(() => {
    // Setup: Create real classification pipeline with mocked AI
    mockAIClient = new MockAIClient();
    const config = validMinimalCategoryConfig as CategoryConfiguration;
    const pipeline = new ClassificationPipeline(config, true, mockAIClient);
    orchestrator = new ClassificationOrchestrator(config, pipeline);
  });

  afterEach(async () => {
    await new Promise((resolve) => setImmediate(resolve));
    mockAIClient.reset();
  });

  describe('Single Email Processing Performance (FR-005)', () => {
    test(
      'should process single email in < 10 seconds (total end-to-end)',
      async () => {
        // Setup: Create realistic test email
        const email = createTestEmail(
          'perf-test-001',
          'Your Amazon order #123456789 has shipped',
          'shipment-tracking@amazon.com',
          'Your package is on the way! Track your shipment at amazon.com/orders'
        );

        // Execute: Measure total processing time
        const startTime = performance.now();
        const result = await orchestrator.classify(email);
        const endTime = performance.now();
        const totalDurationMs = endTime - startTime;

        // Report: Log performance metrics
        console.log(`\n[PERFORMANCE BASELINE] Single Email Processing:`);
        console.log(`  Total Duration: ${formatDuration(totalDurationMs)}`);
        console.log(`  Classification Duration: ${formatDuration(result.processingDurationMs)}`);
        console.log(`  Overhead: ${formatDuration(totalDurationMs - result.processingDurationMs)}`);
        console.log(`  Target: ${formatDuration(PERFORMANCE_THRESHOLDS.MAX_TOTAL_PROCESSING_TIME_MS)}`);
        console.log(
          `  Status: ${totalDurationMs <= PERFORMANCE_THRESHOLDS.MAX_TOTAL_PROCESSING_TIME_MS ? '✓ PASS' : '✗ FAIL'}`
        );

        // Validate: Must meet < 10 second target
        expect(totalDurationMs).toBeLessThanOrEqual(PERFORMANCE_THRESHOLDS.MAX_TOTAL_PROCESSING_TIME_MS);
      },
      TEST_CONFIG.PERFORMANCE_TEST_TIMEOUT_MS
    );

    test(
      'should complete classification in < 5 seconds (classification engine only)',
      async () => {
        // Setup: Create test email
        const email = createTestEmail(
          'perf-test-002',
          'Weekly team meeting notes',
          'project-manager@company.com',
          'Here are the notes from our weekly sync meeting...'
        );

        // Execute: Measure classification time
        const result = await orchestrator.classify(email);
        const classificationDurationMs = result.processingDurationMs;

        // Report: Log classification performance
        console.log(`\n[PERFORMANCE BASELINE] Classification Engine:`);
        console.log(`  Classification Duration: ${formatDuration(classificationDurationMs)}`);
        console.log(`  Target: ${formatDuration(PERFORMANCE_THRESHOLDS.MAX_CLASSIFICATION_TIME_MS)}`);
        console.log(`  Stretch Goal: ${formatDuration(PERFORMANCE_THRESHOLDS.STRETCH_GOAL_MS)}`);
        console.log(
          `  Status: ${classificationDurationMs <= PERFORMANCE_THRESHOLDS.MAX_CLASSIFICATION_TIME_MS ? '✓ PASS' : '✗ FAIL'}`
        );

        // Validate: Classification engine must meet < 5 second target
        expect(classificationDurationMs).toBeLessThanOrEqual(PERFORMANCE_THRESHOLDS.MAX_CLASSIFICATION_TIME_MS);
      },
      TEST_CONFIG.PERFORMANCE_TEST_TIMEOUT_MS
    );

    test(
      'should track performance regression across multiple runs',
      async () => {
        // Setup: Multiple test runs to measure consistency
        const numRuns = 5;
        const durations: number[] = [];

        // Execute: Run classification multiple times
        for (let i = 0; i < numRuns; i++) {
          const email = createTestEmail(
            `perf-test-multi-${i}`,
            `Test email ${i + 1} for regression tracking`,
            'sender@example.com'
          );
          const result = await orchestrator.classify(email);
          durations.push(result.processingDurationMs);
        }

        // Calculate: Statistics
        const avgDuration = durations.reduce((sum, d) => sum + d, 0) / numRuns;
        const maxDuration = Math.max(...durations);
        const minDuration = Math.min(...durations);
        const stdDev = Math.sqrt(
          durations.map((d) => Math.pow(d - avgDuration, 2)).reduce((sum, d) => sum + d, 0) / numRuns
        );

        // Report: Performance statistics
        console.log(`\n[PERFORMANCE BASELINE] Consistency Check (${numRuns} runs):`);
        console.log(`  Average: ${formatDuration(avgDuration)}`);
        console.log(`  Min: ${formatDuration(minDuration)}`);
        console.log(`  Max: ${formatDuration(maxDuration)}`);
        console.log(`  Std Dev: ${formatDuration(stdDev)}`);
        console.log(`  Target: ${formatDuration(PERFORMANCE_THRESHOLDS.MAX_CLASSIFICATION_TIME_MS)}`);
        console.log(
          `  Status: ${avgDuration <= PERFORMANCE_THRESHOLDS.MAX_CLASSIFICATION_TIME_MS ? '✓ PASS' : '✗ FAIL'}`
        );

        // Validate: Average must meet target, consistency should be reasonable
        expect(avgDuration).toBeLessThanOrEqual(PERFORMANCE_THRESHOLDS.MAX_CLASSIFICATION_TIME_MS);
        expect(stdDev).toBeLessThan(avgDuration * 0.5); // Std dev should be < 50% of average
      },
      TEST_CONFIG.PERFORMANCE_TEST_TIMEOUT_MS
    );
  });

  describe('Batch Processing Performance (Constitutional Principle IV)', () => {
    test(
      'should process small batch (10 emails) with reasonable throughput',
      async () => {
        // Setup: Generate batch of test emails
        const emails = generateTestEmailBatch(TEST_CONFIG.BATCH_SIZE_SMALL);
        const memoryBefore = getMemoryUsageMB();

        // Execute: Process batch sequentially (baseline for parallel comparison)
        const startTime = performance.now();
        const results = [];
        for (const email of emails) {
          const result = await orchestrator.classify(email);
          results.push(result);
        }
        const endTime = performance.now();

        const totalDurationMs = endTime - startTime;
        const avgDurationPerEmail = totalDurationMs / emails.length;
        const throughput = (emails.length / totalDurationMs) * 1000; // emails per second
        const memoryAfter = getMemoryUsageMB();
        const memoryGrowth = memoryAfter - memoryBefore;

        // Report: Batch performance metrics
        console.log(`\n[PERFORMANCE BASELINE] Small Batch (${TEST_CONFIG.BATCH_SIZE_SMALL} emails, sequential):`);
        console.log(`  Total Duration: ${formatDuration(totalDurationMs)}`);
        console.log(`  Avg Per Email: ${formatDuration(avgDurationPerEmail)}`);
        console.log(`  Throughput: ${throughput.toFixed(2)} emails/sec`);
        console.log(`  Memory Growth: ${memoryGrowth.toFixed(2)} MB`);
        console.log(`  Min Throughput Target: ${PERFORMANCE_THRESHOLDS.MIN_THROUGHPUT_EMAILS_PER_SECOND} emails/sec`);
        console.log(
          `  Status: ${throughput >= PERFORMANCE_THRESHOLDS.MIN_THROUGHPUT_EMAILS_PER_SECOND ? '✓ PASS' : '✗ FAIL'}`
        );

        // Validate: Each email should meet performance target
        expect(avgDurationPerEmail).toBeLessThanOrEqual(PERFORMANCE_THRESHOLDS.MAX_TOTAL_PROCESSING_TIME_MS);

        // Validate: Throughput should meet minimum target
        expect(throughput).toBeGreaterThanOrEqual(PERFORMANCE_THRESHOLDS.MIN_THROUGHPUT_EMAILS_PER_SECOND);

        // Validate: Memory growth should be reasonable
        expect(memoryGrowth).toBeLessThanOrEqual(PERFORMANCE_THRESHOLDS.MAX_HEAP_GROWTH_MB);
      },
      TEST_CONFIG.PERFORMANCE_TEST_TIMEOUT_MS
    );

    test(
      'should support parallel processing for improved throughput',
      async () => {
        // Setup: Generate batch for parallel testing
        const emails = generateTestEmailBatch(TEST_CONFIG.BATCH_SIZE_SMALL);

        // Execute: Process batch in parallel
        const startTime = performance.now();
        const results = await Promise.all(emails.map((email) => orchestrator.classify(email)));
        const endTime = performance.now();

        const totalDurationMs = endTime - startTime;
        const throughput = (emails.length / totalDurationMs) * 1000; // emails per second

        // Report: Parallel processing performance
        console.log(`\n[PERFORMANCE BASELINE] Parallel Batch (${TEST_CONFIG.BATCH_SIZE_SMALL} emails):`);
        console.log(`  Total Duration: ${formatDuration(totalDurationMs)}`);
        console.log(`  Throughput: ${throughput.toFixed(2)} emails/sec`);
        console.log(`  Optimal Target: ${PERFORMANCE_THRESHOLDS.OPTIMAL_THROUGHPUT_EMAILS_PER_SECOND} emails/sec`);
        console.log(
          `  Status: ${throughput >= PERFORMANCE_THRESHOLDS.OPTIMAL_THROUGHPUT_EMAILS_PER_SECOND ? '✓ PASS' : '✗ FAIL'}`
        );

        // Validate: All emails processed successfully
        expect(results).toHaveLength(emails.length);
        results.forEach((result) => {
          expect(result.selectedLabels).toBeDefined();
        });

        // Validate: Parallel processing should achieve better throughput than sequential
        // (Note: This may fail initially, which is expected in TDD approach)
        expect(throughput).toBeGreaterThanOrEqual(PERFORMANCE_THRESHOLDS.OPTIMAL_THROUGHPUT_EMAILS_PER_SECOND);
      },
      TEST_CONFIG.PERFORMANCE_TEST_TIMEOUT_MS
    );

    test(
      'should handle medium batch (50 emails) with maintained performance',
      async () => {
        // Setup: Generate medium batch
        const emails = generateTestEmailBatch(TEST_CONFIG.BATCH_SIZE_MEDIUM);
        const memoryBefore = getMemoryUsageMB();

        // Execute: Process batch in parallel
        const startTime = performance.now();
        const results = await Promise.all(emails.map((email) => orchestrator.classify(email)));
        const endTime = performance.now();

        const totalDurationMs = endTime - startTime;
        const avgDurationPerEmail = totalDurationMs / emails.length;
        const throughput = (emails.length / totalDurationMs) * 1000;
        const memoryAfter = getMemoryUsageMB();
        const memoryGrowth = memoryAfter - memoryBefore;

        // Report: Medium batch performance
        console.log(`\n[PERFORMANCE BASELINE] Medium Batch (${TEST_CONFIG.BATCH_SIZE_MEDIUM} emails, parallel):`);
        console.log(`  Total Duration: ${formatDuration(totalDurationMs)}`);
        console.log(`  Avg Per Email: ${formatDuration(avgDurationPerEmail)}`);
        console.log(`  Throughput: ${throughput.toFixed(2)} emails/sec`);
        console.log(`  Memory Growth: ${memoryGrowth.toFixed(2)} MB`);
        console.log(
          `  Status: ${throughput >= PERFORMANCE_THRESHOLDS.MIN_THROUGHPUT_EMAILS_PER_SECOND ? '✓ PASS' : '✗ FAIL'}`
        );

        // Validate: Throughput maintained with larger batch
        expect(throughput).toBeGreaterThanOrEqual(PERFORMANCE_THRESHOLDS.MIN_THROUGHPUT_EMAILS_PER_SECOND);

        // Validate: Memory growth scales reasonably
        const memoryPerEmail = memoryGrowth / emails.length;
        expect(memoryPerEmail).toBeLessThan(2); // Less than 2MB per email
      },
      TEST_CONFIG.PERFORMANCE_TEST_TIMEOUT_MS
    );
  });

  describe('Memory Usage Validation', () => {
    test(
      'should not leak memory during batch processing',
      async () => {
        // Setup: Force garbage collection if available (run with --expose-gc flag)
        if (global.gc) {
          global.gc();
        }

        const initialMemory = getMemoryUsageMB();
        const emails = generateTestEmailBatch(TEST_CONFIG.BATCH_SIZE_SMALL);

        // Execute: Process batch
        await Promise.all(emails.map((email) => orchestrator.classify(email)));

        // Allow garbage collection
        await new Promise((resolve) => setTimeout(resolve, 100));
        if (global.gc) {
          global.gc();
        }

        const afterProcessingMemory = getMemoryUsageMB();
        const memoryGrowth = afterProcessingMemory - initialMemory;

        // Report: Memory usage
        console.log(`\n[MEMORY BASELINE] Leak Detection:`);
        console.log(`  Initial Memory: ${initialMemory.toFixed(2)} MB`);
        console.log(`  After Processing: ${afterProcessingMemory.toFixed(2)} MB`);
        console.log(`  Growth: ${memoryGrowth.toFixed(2)} MB`);
        console.log(`  Max Allowed: ${PERFORMANCE_THRESHOLDS.MAX_HEAP_GROWTH_MB} MB`);
        console.log(`  Status: ${memoryGrowth <= PERFORMANCE_THRESHOLDS.MAX_HEAP_GROWTH_MB ? '✓ PASS' : '✗ FAIL'}`);

        // Validate: Memory growth should be reasonable
        expect(memoryGrowth).toBeLessThanOrEqual(PERFORMANCE_THRESHOLDS.MAX_HEAP_GROWTH_MB);
      },
      TEST_CONFIG.PERFORMANCE_TEST_TIMEOUT_MS
    );

    test(
      'should maintain stable memory usage across multiple batches',
      async () => {
        // Setup: Multiple batch runs
        const numBatches = 3;
        const memoryMeasurements: number[] = [];

        // Execute: Process multiple batches
        for (let i = 0; i < numBatches; i++) {
          const emails = generateTestEmailBatch(5); // Smaller batches for faster test
          await Promise.all(emails.map((email) => orchestrator.classify(email)));

          // Measure memory after each batch
          await new Promise((resolve) => setTimeout(resolve, 100));
          if (global.gc) {
            global.gc();
          }
          memoryMeasurements.push(getMemoryUsageMB());
        }

        // Calculate: Memory stability
        const maxMemory = Math.max(...memoryMeasurements);
        const minMemory = Math.min(...memoryMeasurements);
        const memoryRange = maxMemory - minMemory;

        // Report: Memory stability
        console.log(`\n[MEMORY BASELINE] Stability Across ${numBatches} Batches:`);
        console.log(`  Min: ${minMemory.toFixed(2)} MB`);
        console.log(`  Max: ${maxMemory.toFixed(2)} MB`);
        console.log(`  Range: ${memoryRange.toFixed(2)} MB`);
        console.log(`  Status: ${memoryRange <= PERFORMANCE_THRESHOLDS.MAX_HEAP_GROWTH_MB ? '✓ PASS' : '✗ FAIL'}`);

        // Validate: Memory should not grow unbounded
        expect(memoryRange).toBeLessThanOrEqual(PERFORMANCE_THRESHOLDS.MAX_HEAP_GROWTH_MB);
      },
      TEST_CONFIG.PERFORMANCE_TEST_TIMEOUT_MS
    );
  });

  describe('Throughput Metrics', () => {
    test(
      'should calculate accurate throughput metrics',
      async () => {
        // Setup: Fixed batch size for throughput calculation
        const batchSize = 20;
        const emails = generateTestEmailBatch(batchSize);

        // Execute: Process with timing
        const startTime = performance.now();
        const results = await Promise.all(emails.map((email) => orchestrator.classify(email)));
        const endTime = performance.now();

        const totalDurationSec = (endTime - startTime) / 1000;
        const throughput = batchSize / totalDurationSec;
        const avgTimePerEmail = totalDurationSec / batchSize;

        // Report: Throughput metrics
        console.log(`\n[THROUGHPUT BASELINE] Batch Size ${batchSize}:`);
        console.log(`  Total Duration: ${totalDurationSec.toFixed(2)}s`);
        console.log(`  Throughput: ${throughput.toFixed(3)} emails/sec`);
        console.log(`  Avg Time Per Email: ${avgTimePerEmail.toFixed(2)}s`);
        console.log(`  Min Target: ${PERFORMANCE_THRESHOLDS.MIN_THROUGHPUT_EMAILS_PER_SECOND} emails/sec`);
        console.log(`  Optimal Target: ${PERFORMANCE_THRESHOLDS.OPTIMAL_THROUGHPUT_EMAILS_PER_SECOND} emails/sec`);

        // Validate: Should meet minimum throughput
        expect(throughput).toBeGreaterThanOrEqual(PERFORMANCE_THRESHOLDS.MIN_THROUGHPUT_EMAILS_PER_SECOND);

        // Validate: All emails processed successfully
        expect(results).toHaveLength(batchSize);
      },
      TEST_CONFIG.PERFORMANCE_TEST_TIMEOUT_MS
    );
  });

  describe('Performance Profiling Data Collection', () => {
    test(
      'should collect detailed stage timing data for profiling',
      async () => {
        // Setup: Create test email
        const email = createTestEmail(
          'profile-test-001',
          'Test email for stage profiling',
          'sender@example.com'
        );

        // Execute: Classify and extract timing data
        const result = await orchestrator.classify(email);

        // Validate: Explainability trace should contain stage timing information
        expect(result.explainabilityTrace).toBeDefined();

        // Note: T073 will add detailed stage timing to explainability traces
        // This test validates the infrastructure is in place
        console.log(`\n[PROFILING DATA] Stage Timing Infrastructure:`);
        console.log(`  Total Processing: ${formatDuration(result.processingDurationMs)}`);
        console.log(`  Explainability Trace Present: ${result.explainabilityTrace ? '✓' : '✗'}`);
        console.log(`  Ready for T073 Stage Profiling: ✓`);

        // Basic validation
        expect(result.processingDurationMs).toBeGreaterThan(0);
      },
      TEST_CONFIG.PERFORMANCE_TEST_TIMEOUT_MS
    );
  });
});

