describe('Pipeline Path Performance (AI vs Non-AI)', () => {
  test(
    'should complete rule-based path in < 1 second (no AI augmentation)',
    async () => {
      // Setup: Email that will NOT trigger AI (high confidence rule-based match)
      // Using clear domain-based category trigger for high confidence
      const email = createTestEmail(
        'perf-rule-based-001',
        'Invoice #INV-2025-12345 from Stripe',
        'billing@stripe.com',
        'Your invoice for $99.00 is attached. Payment due in 30 days.'
      );

      // Execute: Measure rule-based processing time
      const startTime = performance.now();
      const result = await orchestrator.classify(email);
      const endTime = performance.now();
      const totalDurationMs = endTime - startTime;

      // Report: Rule-based path performance
      console.log(`\n[PERFORMANCE BASELINE] Rule-Based Path (No AI):`);
      console.log(`  Processing Duration: ${formatDuration(totalDurationMs)}`);
      console.log(`  AI Triggered: ${result.needsAiClassification ? 'YES' : 'NO'}`);
      console.log(`  Target: ${formatDuration(PERFORMANCE_THRESHOLDS.MAX_RULE_BASED_PROCESSING_MS)}`);
      console.log(
        `  Status: ${totalDurationMs <= PERFORMANCE_THRESHOLDS.MAX_RULE_BASED_PROCESSING_MS ? '✓ PASS' : '✗ FAIL'}`
      );

      // Validate: Should NOT trigger AI (high confidence)
      expect(result.needsAiClassification).toBe(false);

      // Validate: Rule-based path must meet < 1 second target
      expect(totalDurationMs).toBeLessThanOrEqual(PERFORMANCE_THRESHOLDS.MAX_RULE_BASED_PROCESSING_MS);
    },
    TEST_CONFIG.PERFORMANCE_TEST_TIMEOUT_MS
  );

  test(
    'should complete AI augmentation path in < 10 seconds (with AI)',
    async () => {
      // Setup: Ambiguous email that will trigger AI (low confidence)
      // Generic content without clear categorization signals
      const email = createTestEmail(
        'perf-ai-path-001',
        'Quick question',
        'unknown@random-domain.com',
        'Hey, just wanted to follow up on our previous conversation. Let me know when you have a chance.'
      );

      // Execute: Measure AI-augmented processing time
      const startTime = performance.now();
      const result = await orchestrator.classify(email);
      const endTime = performance.now();
      const totalDurationMs = endTime - startTime;

      // Report: AI augmentation path performance
      console.log(`\n[PERFORMANCE BASELINE] AI Augmentation Path:`);
      console.log(`  Processing Duration: ${formatDuration(totalDurationMs)}`);
      console.log(`  AI Triggered: ${result.needsAiClassification ? 'YES' : 'NO'}`);
      console.log(`  Target: ${formatDuration(PERFORMANCE_THRESHOLDS.MAX_TOTAL_PROCESSING_TIME_MS)}`);
      console.log(
        `  Status: ${totalDurationMs <= PERFORMANCE_THRESHOLDS.MAX_TOTAL_PROCESSING_TIME_MS ? '✓ PASS' : '✗ FAIL'}`
      );

      // Note: With MockAIClient, AI stages complete instantly
      // In production, this test will measure real OpenAI API latency
      console.log(`  Note: MockAIClient used - production will have ~3-5s OpenAI API latency`);

      // Validate: Total time must meet < 10 second target (even with AI)
      expect(totalDurationMs).toBeLessThanOrEqual(PERFORMANCE_THRESHOLDS.MAX_TOTAL_PROCESSING_TIME_MS);
    },
    TEST_CONFIG.PERFORMANCE_TEST_TIMEOUT_MS
  );

  test(
    'should show performance difference between AI and non-AI paths',
    async () => {
      // Setup: One email for each path
      const ruleBasedEmail = createTestEmail(
        'perf-comparison-rule',
        'Receipt for order #12345',
        'receipts@store.com',
        'Thank you for your purchase. Your receipt is attached.'
      );

      const aiPathEmail = createTestEmail(
        'perf-comparison-ai',
        'Thoughts?',
        'person@example.com',
        'What do you think about the proposal we discussed last week?'
      );

      // Execute: Measure both paths
      const ruleBasedStart = performance.now();
      const ruleBasedResult = await orchestrator.classify(ruleBasedEmail);
      const ruleBasedEnd = performance.now();
      const ruleBasedDuration = ruleBasedEnd - ruleBasedStart;

      const aiPathStart = performance.now();
      const aiPathResult = await orchestrator.classify(aiPathEmail);
      const aiPathEnd = performance.now();
      const aiPathDuration = aiPathEnd - aiPathStart;

      // Report: Path comparison
      console.log(`\n[PERFORMANCE BASELINE] Path Comparison:`);
      console.log(`  Rule-Based Path: ${formatDuration(ruleBasedDuration)} (AI: ${ruleBasedResult.needsAiClassification ? 'YES' : 'NO'})`);
      console.log(`  AI Path: ${formatDuration(aiPathDuration)} (AI: ${aiPathResult.needsAiClassification ? 'YES' : 'NO'})`);
      console.log(
        `  Performance Ratio: ${aiPathResult.needsAiClassification ? `${(aiPathDuration / ruleBasedDuration).toFixed(2)}x slower (expected with AI)` : 'Both rule-based'}`
      );

      // Note: With MockAIClient, both paths are fast
      // In production, AI path should be ~5-10x slower due to API latency
      console.log(`  Note: With real OpenAI API, expect AI path to be 5-10x slower than rule-based`);

      // Validate: Both paths meet their respective targets
      expect(ruleBasedDuration).toBeLessThanOrEqual(PERFORMANCE_THRESHOLDS.MAX_RULE_BASED_PROCESSING_MS);
      expect(aiPathDuration).toBeLessThanOrEqual(PERFORMANCE_THRESHOLDS.MAX_TOTAL_PROCESSING_TIME_MS);
    },
    TEST_CONFIG.PERFORMANCE_TEST_TIMEOUT_MS
  );
});

