        expect(results).toHaveLength(emails.length);
        results.forEach((result) => {
          expect(result.selectedLabels).toBeDefined();
        });

        // Validate: Parallel processing should achieve better throughput than sequential
        // (Note: This may fail initially, which is expected in TDD approach)
        expect(throughput).toBeGreaterThanOrEqual(PERFORMANCE_THRESHOLDS.OPTIMAL_THROUGHPUT_EMAILS_PER_SECOND);
      },
      TEST_CONFIG.PERFORMANCE_TEST_TIMEOUT_MS
    );

    test(
      'should handle medium batch (50 emails) with maintained performance',
      async () => {
        // Setup: Generate medium batch
        const emails = generateTestEmailBatch(TEST_CONFIG.BATCH_SIZE_MEDIUM);
        const memoryBefore = getMemoryUsageMB();

        // Execute: Process batch in parallel
        const startTime = performance.now();
        const results = await Promise.all(emails.map((email) => orchestrator.classify(email)));
        const endTime = performance.now();

        const totalDurationMs = endTime - startTime;
        const avgDurationPerEmail = totalDurationMs / emails.length;
        const throughput = (emails.length / totalDurationMs) * 1000;
        const memoryAfter = getMemoryUsageMB();
        const memoryGrowth = memoryAfter - memoryBefore;

        // Report: Medium batch performance
        console.log(`\n[PERFORMANCE BASELINE] Medium Batch (${TEST_CONFIG.BATCH_SIZE_MEDIUM} emails, parallel):`);
        console.log(`  Total Duration: ${formatDuration(totalDurationMs)}`);
        console.log(`  Avg Per Email: ${formatDuration(avgDurationPerEmail)}`);
        console.log(`  Throughput: ${throughput.toFixed(2)} emails/sec`);
        console.log(`  Memory Growth: ${memoryGrowth.toFixed(2)} MB`);
        console.log(
          `  Status: ${throughput >= PERFORMANCE_THRESHOLDS.MIN_THROUGHPUT_EMAILS_PER_SECOND ? '✓ PASS' : '✗ FAIL'}`
        );

        // Validate: All emails processed successfully
        expect(results).toHaveLength(emails.length);
        results.forEach((result) => {
          expect(result.selectedLabels).toBeDefined();
        });

        // Validate: Throughput maintained with larger batch
        expect(throughput).toBeGreaterThanOrEqual(PERFORMANCE_THRESHOLDS.MIN_THROUGHPUT_EMAILS_PER_SECOND);

        // Validate: Memory growth scales reasonably
        const memoryPerEmail = memoryGrowth / emails.length;
        expect(memoryPerEmail).toBeLessThan(2); // Less than 2MB per email
      },
      TEST_CONFIG.PERFORMANCE_TEST_TIMEOUT_MS
    );
  });

  describe('Memory Usage Validation', () => {
    test(
      'should not leak memory during batch processing',
      async () => {
        // Setup: Force garbage collection if available (run with --expose-gc flag)
        if (global.gc) {
          global.gc();
        }

        const initialMemory = getMemoryUsageMB();
        const emails = generateTestEmailBatch(TEST_CONFIG.BATCH_SIZE_SMALL);

        // Execute: Process batch
        await Promise.all(emails.map((email) => orchestrator.classify(email)));

        // Allow garbage collection
        await new Promise((resolve) => setTimeout(resolve, 100));
        if (global.gc) {
          global.gc();
        }

        const afterProcessingMemory = getMemoryUsageMB();
        const memoryGrowth = afterProcessingMemory - initialMemory;

        // Report: Memory usage
        console.log(`\n[MEMORY BASELINE] Leak Detection:`);
        console.log(`  Initial Memory: ${initialMemory.toFixed(2)} MB`);
        console.log(`  After Processing: ${afterProcessingMemory.toFixed(2)} MB`);
        console.log(`  Growth: ${memoryGrowth.toFixed(2)} MB`);
        console.log(`  Max Allowed: ${PERFORMANCE_THRESHOLDS.MAX_HEAP_GROWTH_MB} MB`);
        console.log(`  Status: ${memoryGrowth <= PERFORMANCE_THRESHOLDS.MAX_HEAP_GROWTH_MB ? '✓ PASS' : '✗ FAIL'}`);

        // Validate: Memory growth should be reasonable
        expect(memoryGrowth).toBeLessThanOrEqual(PERFORMANCE_THRESHOLDS.MAX_HEAP_GROWTH_MB);
      },
      TEST_CONFIG.PERFORMANCE_TEST_TIMEOUT_MS
    );

    test(
      'should maintain stable memory usage across multiple batches',
      async () => {
        // Setup: Multiple batch runs
        const numBatches = 3;
        const memoryMeasurements: number[] = [];

        // Execute: Process multiple batches
        for (let i = 0; i < numBatches; i++) {
          const emails = generateTestEmailBatch(5); // Smaller batches for faster test
          await Promise.all(emails.map((email) => orchestrator.classify(email)));

          // Measure memory after each batch
          await new Promise((resolve) => setTimeout(resolve, 100));
          if (global.gc) {
            global.gc();
          }
          memoryMeasurements.push(getMemoryUsageMB());
        }

        // Calculate: Memory stability
        const maxMemory = Math.max(...memoryMeasurements);
        const minMemory = Math.min(...memoryMeasurements);
        const memoryRange = maxMemory - minMemory;

        // Report: Memory stability
        console.log(`\n[MEMORY BASELINE] Stability Across ${numBatches} Batches:`);
        console.log(`  Min: ${minMemory.toFixed(2)} MB`);
        console.log(`  Max: ${maxMemory.toFixed(2)} MB`);
        console.log(`  Range: ${memoryRange.toFixed(2)} MB`);
        console.log(`  Status: ${memoryRange <= PERFORMANCE_THRESHOLDS.MAX_HEAP_GROWTH_MB ? '✓ PASS' : '✗ FAIL'}`);

        // Validate: Memory should not grow unbounded
        expect(memoryRange).toBeLessThanOrEqual(PERFORMANCE_THRESHOLDS.MAX_HEAP_GROWTH_MB);
      },
      TEST_CONFIG.PERFORMANCE_TEST_TIMEOUT_MS
    );
  });

  describe('Throughput Metrics', () => {
    test(
      'should calculate accurate throughput metrics',
      async () => {
        // Setup: Fixed batch size for throughput calculation
        const batchSize = 20;
        const emails = generateTestEmailBatch(batchSize);

        // Execute: Process with timing
        const startTime = performance.now();
        const results = await Promise.all(emails.map((email) => orchestrator.classify(email)));
        const endTime = performance.now();

        const totalDurationSec = (endTime - startTime) / 1000;
        const throughput = batchSize / totalDurationSec;
        const avgTimePerEmail = totalDurationSec / batchSize;

        // Report: Throughput metrics
        console.log(`\n[THROUGHPUT BASELINE] Batch Size ${batchSize}:`);
        console.log(`  Total Duration: ${totalDurationSec.toFixed(2)}s`);
        console.log(`  Throughput: ${throughput.toFixed(3)} emails/sec`);
        console.log(`  Avg Time Per Email: ${avgTimePerEmail.toFixed(2)}s`);
        console.log(`  Min Target: ${PERFORMANCE_THRESHOLDS.MIN_THROUGHPUT_EMAILS_PER_SECOND} emails/sec`);
        console.log(`  Optimal Target: ${PERFORMANCE_THRESHOLDS.OPTIMAL_THROUGHPUT_EMAILS_PER_SECOND} emails/sec`);

        // Validate: Should meet minimum throughput
        expect(throughput).toBeGreaterThanOrEqual(PERFORMANCE_THRESHOLDS.MIN_THROUGHPUT_EMAILS_PER_SECOND);

        // Validate: All emails processed successfully
        expect(results).toHaveLength(batchSize);
      },
      TEST_CONFIG.PERFORMANCE_TEST_TIMEOUT_MS
    );
  });

  describe('Performance Profiling Data Collection', () => {
    test(
      'should collect detailed stage timing data for profiling',
      async () => {
        // Setup: Create test email
        const email = createTestEmail(
          'profile-test-001',
          'Test email for stage profiling',
          'sender@example.com'
        );

        // Execute: Classify and extract timing data
        const result = await orchestrator.classify(email);

        // Validate: Explainability trace should contain stage timing information
        expect(result.explainabilityTrace).toBeDefined();

        // Note: T073 will add detailed stage timing to explainability traces
        // This test validates the infrastructure is in place
        console.log(`\n[PROFILING DATA] Stage Timing Infrastructure:`);
        console.log(`  Total Processing: ${formatDuration(result.processingDurationMs)}`);
        console.log(`  Explainability Trace Present: ${result.explainabilityTrace ? '✓' : '✗'}`);
        console.log(`  Ready for T073 Stage Profiling: ✓`);

        // Basic validation
        expect(result.processingDurationMs).toBeGreaterThan(0);
      },
      TEST_CONFIG.PERFORMANCE_TEST_TIMEOUT_MS
    );
  });
});

