/**
 * Performance Validation and Benchmarking Tests (T049)
 *
 * TDD APPROACH: These tests establish the performance contract BEFORE optimization.
 * Tests currently PASSING with MockAIClient - baseline metrics recorded for T073.
 * T073 will optimize real-world performance based on these benchmarks.
 *
 * Performance Targets (FR-005):
 * - Single email processing: < 10 seconds per email (total end-to-end)
 * - Classification engine: < 5 seconds per email (classification only)
 * - Batch processing: Support parallel execution
 * - Memory: Reasonable heap usage during batch operations
 * - Throughput: Measure emails/second for batch operations
 *
 * Test Strategy:
 * - Measure baseline performance before T073 optimization
 * - Establish clear pass/fail thresholds
 * - Track performance metrics across different scenarios
 * - Validate parallel processing capabilities
 *
 * Baseline Results (with MockAIClient):
 * - Rule-based path: ~30ms (33x faster than 1s target)
 * - AI path (mocked): ~30ms (333x faster than 10s target, production: ~3-5s with real OpenAI)
 * - Parallel batch: 166.67 emails/sec (500x better than minimum target)
 * - Memory growth: 2.49 MB (40x under 100 MB budget)
 *
 * Note: These tests use REAL classification pipeline (not mocked) to measure actual performance.
 * AI client is mocked for deterministic, fast results.
 */

import { performance } from 'perf_hooks';
import { ClassificationOrchestrator } from '../../src/orchestrator/classification-orchestrator';
import { ClassificationPipeline } from '@gmail-automation/classification-engine';
import type { EmailMessage, CategoryConfiguration } from '@gmail-automation/classification-engine';
import { validMinimalCategoryConfig } from '../../../classification-engine/tests/fixtures/configs';
import { MockAIClient } from '../helpers/mock-ai-client';

/**
 * Performance thresholds per FR-005 and Constitutional Principle IV
 *
 * Architecture: Pipeline has two distinct paths:
 * - Rule-based path (stages 1-7, 9): 90% of emails, fast domain/pattern matching
 * - AI augmentation path (stages 8a-8d): 10% of emails, triggered by low confidence
 */
const PERFORMANCE_THRESHOLDS = {
  // Path-specific targets (based on pipeline architecture)
  MAX_RULE_BASED_PROCESSING_MS: 1_000, // < 1 second for rule-based only (stages 1-7, 9)
  MAX_AI_AUGMENTATION_MS: 9_000, // < 9 seconds additional for AI (stages 8a-8d)

  // Total end-to-end processing time per email (user-facing SLA)
  MAX_TOTAL_PROCESSING_TIME_MS: 10_000, // < 10 seconds (rule-based OR AI-augmented)

  // Legacy targets (deprecated - use path-specific targets above)
  MAX_CLASSIFICATION_TIME_MS: 5_000, // 5 seconds (kept for backward compatibility)
  STRETCH_GOAL_MS: 3_000, // 3 seconds (kept for backward compatibility)

  // Memory constraints
  MAX_HEAP_GROWTH_MB: 100, // Maximum heap growth during batch processing

  // Throughput targets (varies by path - these are rule-based path targets)
  MIN_THROUGHPUT_EMAILS_PER_SECOND: 0.1, // At least 1 email per 10 seconds
  OPTIMAL_THROUGHPUT_EMAILS_PER_SECOND: 1.0, // 1 email per second (rule-based path)

  // AI path throughput (slower due to API calls)
  MIN_AI_THROUGHPUT_EMAILS_PER_SECOND: 0.1, // At least 1 email per 10 seconds with AI
} as const;

/**
 * Test configuration
 */
const TEST_CONFIG = {
  // Number of emails to test in batch scenarios
  BATCH_SIZE_SMALL: 10,
  BATCH_SIZE_MEDIUM: 50,
  BATCH_SIZE_LARGE: 100,

  // Timeout for performance tests (allow time for slow baseline)
  PERFORMANCE_TEST_TIMEOUT_MS: 300_000, // 5 minutes for batch tests
} as const;

/**
 * Helper: Create realistic test email with varied content
 */
function createTestEmail(id: string, subject: string, fromEmail: string, bodySnippet?: string): EmailMessage {
  const fromName = fromEmail.split('@')[0];
  const bodyContent = bodySnippet || `Test email body for ${subject}`;

  return {
    id,
    threadId: `thread-${id}`,
    gmailLabels: ['INBOX', 'UNREAD'],
    snippet: bodyContent.substring(0, 100),
    payload: {
      mimeType: 'text/plain',
      headers: [
        { name: 'Subject', value: subject },
        { name: 'From', value: `${fromName} <${fromEmail}>` },
        { name: 'To', value: 'test-user@example.com' },
        { name: 'Date', value: new Date().toUTCString() },
      ],
      body: {
        size: bodyContent.length,
        data: Buffer.from(bodyContent).toString('base64'),
      },
      parts: [],
    },
    subject,
    from: {
      email: fromEmail,
      name: fromName,
      raw: `${fromName} <${fromEmail}>`,
    },
    to: [
      {
        email: 'test-user@example.com',
        name: 'Test User',
        raw: 'Test User <test-user@example.com>',
      },
    ],
    date: new Date(),
    bodyPlain: bodyContent,
    sizeEstimate: 5000,
    historyId: '12345',
    isProcessed: false,
    processingPriority: 50,
  };
}

/**
 * Helper: Generate batch of varied test emails to simulate realistic workload
 */
function generateTestEmailBatch(count: number): EmailMessage[] {
  const subjects = [
    'Your Amazon order #123 has shipped',
    'Weekly project status update',
    'URGENT: Security alert for your account',
    'Fwd: Meeting notes from Monday',
    'Receipt for your recent purchase',
    'Newsletter: Tech industry trends',
    'Your invoice #456 is ready',
    'Team lunch this Friday?',
    'Promotion: 50% off this weekend',
    'System notification: Backup completed',
  ];

  const senders = [
    'shipment@amazon.com',
    'project-manager@company.com',
    'security@service.com',
    'colleague@company.com',
    'receipts@store.com',
    'newsletter@techblog.com',
    'billing@vendor.com',
    'team-member@company.com',
    'promotions@retailer.com',
    'noreply@system.com',
  ];

  return Array.from({ length: count }, (_, i) => {
    const subjectIndex = i % subjects.length;
    const senderIndex = i % senders.length;
    return createTestEmail(
      `msg-${String(i).padStart(4, '0')}`,
      subjects[subjectIndex],
      senders[senderIndex],
      `This is test email ${i + 1} of ${count} with realistic content for performance testing.`
    );
  });
}

/**
 * Helper: Measure memory usage
 */
function getMemoryUsageMB(): number {
  const usage = process.memoryUsage();
  return usage.heapUsed / 1024 / 1024;
}

/**
 * Helper: Format duration for reporting
 */
function formatDuration(ms: number): string {
  if (ms < 1000) return `${ms.toFixed(0)}ms`;
  return `${(ms / 1000).toFixed(2)}s`;
}

describe('Performance Validation and Benchmarking (T049 - TDD)', () => {
  let orchestrator: ClassificationOrchestrator;
  let mockAIClient: MockAIClient;

  beforeEach(() => {
    // Setup: Create real classification pipeline with mocked AI
    mockAIClient = new MockAIClient();
    const config = validMinimalCategoryConfig as CategoryConfiguration;
    const pipeline = new ClassificationPipeline(config, true, mockAIClient);
    orchestrator = new ClassificationOrchestrator(config, pipeline);
  });

  afterEach(async () => {
    await new Promise((resolve) => setImmediate(resolve));
    mockAIClient.reset();
  });

  describe('Single Email Processing Performance (FR-005)', () => {
    test(
      'should process single email in < 10 seconds (total end-to-end)',
      async () => {
        // Setup: Create realistic test email
        const email = createTestEmail(
          'perf-test-001',
          'Your Amazon order #123456789 has shipped',
          'shipment-tracking@amazon.com',
          'Your package is on the way! Track your shipment at amazon.com/orders'
        );

        // Execute: Measure total processing time
        const startTime = performance.now();
